import { z } from 'zod';

// ── LLM output schemas ──────────────────────────────────────────────────────

/** A single task inside a decomposed module. */
export const decomposeTaskSchema = z.object({
	title: z.string().min(1, 'Task title is required').max(500, 'Task title too long'),
	description: z.string().max(5000).optional()
});
export type DecomposeTask = z.infer<typeof decomposeTaskSchema>;

/** A single decomposed module produced by the LLM. */
export const decomposeModuleSchema = z.object({
	name: z.string().min(1, 'Module name is required').max(200, 'Module name too long'),
	description: z.string().max(5000).optional(),
	tasks: z.array(decomposeTaskSchema).min(0)
});
export type DecomposeModule = z.infer<typeof decomposeModuleSchema>;

// ── SSE event types ─────────────────────────────────────────────────────────

/** Union discriminator for SSE events sent to the frontend. */
export type DecomposeEvent = DecomposeModuleEvent | DecomposeErrorEvent | DecomposeDoneEvent;

/** A successfully parsed and validated module chunk. */
export interface DecomposeModuleEvent {
	type: 'module';
	index: number;
	module: DecomposeModule;
}

/** An error occurred during the decompose stream. */
export interface DecomposeErrorEvent {
	type: 'error';
	stage: 'connecting' | 'streaming' | 'parsing';
	message: string;
}

/** Signal that the stream is complete. */
export interface DecomposeDoneEvent {
	type: 'done';
	total: number;
	errors: number;
}

import { sqliteTable, text, integer, index } from 'drizzle-orm/sqlite-core';
import { sql } from 'drizzle-orm';

// ── Status enums (stored as text in SQLite, validated by Zod at app layer) ──

export const milestoneStatusEnum = ['draft', 'in-progress', 'completed', 'archived'] as const;
export type MilestoneStatus = (typeof milestoneStatusEnum)[number];

export const moduleStatusEnum = ['draft', 'in-progress', 'completed'] as const;
export type ModuleStatus = (typeof moduleStatusEnum)[number];

export const taskStatusEnum = [
	'todo',
	'in-progress',
	'blocked',
	'review',
	'done',
	'skipped'
] as const;
export type TaskStatus = (typeof taskStatusEnum)[number];

// ── Milestone ────────────────────────────────────────────────────────────────
// Primary entity. ID format: MS-{seq} (e.g. MS-1, MS-2).

export const milestones = sqliteTable(
	'milestones',
	{
		id: text('id').primaryKey(), // MS-{seq}
		title: text('title').notNull(),
		sourceMd: text('source_md'),
		gitUrl: text('git_url'),
		status: text('status', { enum: milestoneStatusEnum }).notNull().default('draft'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`)
	},
	(table) => [index('milestone_status_idx').on(table.status)]
);

// ── Module ───────────────────────────────────────────────────────────────────
// Groups tasks within a milestone. ID format: MOD-{milestone_seq}-{seq}.

export const modules = sqliteTable(
	'modules',
	{
		id: text('id').primaryKey(), // MOD-{ms_seq}-{seq}
		milestoneId: text('milestone_id')
			.notNull()
			.references(() => milestones.id, { onDelete: 'cascade' }),
		name: text('name').notNull(),
		description: text('description'),
		status: text('status', { enum: moduleStatusEnum }).notNull().default('draft'),
		sortOrder: integer('sort_order').notNull().default(0)
	},
	(table) => [
		index('module_milestone_id_idx').on(table.milestoneId),
		index('module_status_idx').on(table.status)
	]
);

// ── Task ─────────────────────────────────────────────────────────────────────
// Atomic unit of work. ID format: TASK-{global_seq}.
// short_id is a global auto-increment for human-friendly references.

export const tasks = sqliteTable(
	'tasks',
	{
		id: text('id').primaryKey(), // TASK-{global_seq}
		shortId: integer('short_id').notNull().unique(), // global auto-increment
		moduleId: text('module_id')
			.notNull()
			.references(() => modules.id, { onDelete: 'cascade' }),
		title: text('title').notNull(),
		description: text('description'),
		references: text('references'), // JSON or text blob
		status: text('status', { enum: taskStatusEnum }).notNull().default('todo'),
		assignee: text('assignee'),
		subTotal: integer('sub_total').notNull().default(0),
		subDone: integer('sub_done').notNull().default(0),
		progressMessage: text('progress_message'),
		commitHash: text('commit_hash'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		updatedAt: integer('updated_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		reportedAt: integer('reported_at', { mode: 'timestamp' })
	},
	(table) => [
		index('task_status_module_idx').on(table.status, table.moduleId),
		index('task_status_reported_idx').on(table.status, table.reportedAt),
		index('task_module_id_idx').on(table.moduleId),
		index('task_short_id_idx').on(table.shortId)
	]
);

// ── Type exports for use in application code ──

export type Milestone = typeof milestones.$inferSelect;
export type NewMilestone = typeof milestones.$inferInsert;
export type Module = typeof modules.$inferSelect;
export type NewModule = typeof modules.$inferInsert;
export type Task = typeof tasks.$inferSelect;
export type NewTask = typeof tasks.$inferInsert;

import { json, error } from '@sveltejs/kit';
import type { PageServerLoad } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';

export const load: PageServerLoad = async ({ params }) => {
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		throw error(404, `里程碑 ${params.id} 不存在`);
	}
	return { milestone };
};

/**
 * Lightweight POST-based SSE client.
 *
 * Standard EventSource only supports GET, so this uses fetch + ReadableStream
 * to consume SSE events from a POST endpoint. Parses the `event:` / `data:`
 * fields and dispatches typed callbacks.
 */

import type { DecomposeModule, DecomposeEvent } from '$lib/schemas/decompose.js';

// ── Types ───────────────────────────────────────────────────────────────────

export interface PostSseCallbacks {
	onModule?: (index: number, module: DecomposeModule) => void;
	onError?: (stage: string, message: string) => void;
	onDone?: (total: number, errors: number) => void;
}

export interface PostSseResult {
	abort: () => void;
}

// ── SSE parser ──────────────────────────────────────────────────────────────

/**
 * Parse a raw SSE text buffer into individual events.
 * Handles the standard SSE format: `event: <name>\ndata: <json>\n\n`.
 *
 * Returns parsed events and any leftover text that may be an incomplete event.
 */
function parseSseBuffer(buffer: string): { events: DecomposeEvent[]; remaining: string } {
	const events: DecomposeEvent[] = [];
	const parts = buffer.split('\n\n');
	// The last part may be incomplete (no trailing \n\n yet)
	const remaining = parts.pop() ?? '';

	for (const part of parts) {
		const event = parseSingleSseEvent(part.trim());
		if (event) events.push(event);
	}

	return { events, remaining };
}

function parseSingleSseEvent(block: string): DecomposeEvent | null {
	let eventType = '';
	let dataStr = '';

	for (const line of block.split('\n')) {
		if (line.startsWith('event:')) {
			eventType = line.slice(6).trim();
		} else if (line.startsWith('data:')) {
			dataStr = line.slice(5).trimStart();
		}
	}

	if (!dataStr) return null;

	try {
		const parsed = JSON.parse(dataStr) as DecomposeEvent;
		// Prefer the SSE event field; fallback to the parsed type field
		if (eventType && !parsed.type) {
			(parsed as any).type = eventType;
		}
		return parsed;
	} catch {
		console.warn('[sse-client] Failed to parse SSE data:', dataStr.slice(0, 200));
		return null;
	}
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Send a POST request and consume the response as an SSE stream.
 *
 * @param url      - The endpoint URL
 * @param body     - The JSON body to POST
 * @param callbacks - Event callbacks (onModule, onError, onDone)
 * @returns An object with an `abort()` method to cancel the stream
 */
export function postSse(url: string, body: Record<string, unknown>, callbacks: PostSseCallbacks): PostSseResult {
	const controller = new AbortController();
	let buffer = '';

	fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify(body),
		signal: controller.signal
	})
		.then(async (response) => {
			if (!response.ok) {
				// Server returned a non-200 before streaming started
				const errorBody = await response.text().catch(() => 'Unknown error');
				callbacks.onError?.('connecting', `HTTP ${response.status}: ${errorBody.slice(0, 500)}`);
				callbacks.onDone?.(0, 1);
				return;
			}

			const reader = response.body?.getReader();
			if (!reader) {
				callbacks.onError?.('connecting', 'Response body is not readable');
				callbacks.onDone?.(0, 1);
				return;
			}

			const decoder = new TextDecoder();

			try {
				while (true) {
					const { done, value } = await reader.read();
					if (done) break;

					buffer += decoder.decode(value, { stream: true });
					const { events, remaining } = parseSseBuffer(buffer);
					buffer = remaining;

					for (const event of events) {
						switch (event.type) {
							case 'module':
								callbacks.onModule?.(event.index, event.module);
								break;
							case 'error':
								callbacks.onError?.(event.stage, event.message);
								break;
							case 'done':
								callbacks.onDone?.(event.total, event.errors);
								break;
						}
					}
				}

				// Process any remaining buffer (final chunk)
				if (buffer.trim()) {
					const { events } = parseSseBuffer(buffer + '\n\n');
					for (const event of events) {
						switch (event.type) {
							case 'module':
								callbacks.onModule?.(event.index, event.module);
								break;
							case 'error':
								callbacks.onError?.(event.stage, event.message);
								break;
							case 'done':
								callbacks.onDone?.(event.total, event.errors);
								break;
						}
					}
				}
			} catch (err: any) {
				if (err.name !== 'AbortError') {
					callbacks.onError?.('streaming', err.message ?? 'Stream read error');
					callbacks.onDone?.(0, 1);
				}
			}
		})
		.catch((err: any) => {
			if (err.name !== 'AbortError') {
				callbacks.onError?.('connecting', err.message ?? 'Network error');
				callbacks.onDone?.(0, 1);
			}
		});

	return { abort: () => controller.abort() };
}

